# Skeptic review S42-T1-A-E2: verify PASS/CONTINUE only on taught contract
def assess(record: dict) -> str:
    required = {'extra_policy', 'json_schema', 'valid_fixture', 'case_id', 'business_rule'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not (record["extra_policy"] == "allow" and not record["business_rule"]) else "REJECT_SCHEMA"

valid = {'case_id': 'CASO-CUS-042-1A', 'extra_policy': 'forbid', 'json_schema': True, 'valid_fixture': True, 'business_rule': True}
invalid = {'case_id': 'CASO-CUS-042-1A', 'extra_policy': 'forbid', 'json_schema': True, 'valid_fixture': True, 'business_rule': True, '_adversarial': True}
incomplete = {**valid}
incomplete.pop('business_rule', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

